import{_ as a,o as i,c as r,ag as t}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Product Suite","description":"Overview of the three public plugins in the Bamdra OpenClaw suite.","frontmatter":{"title":"Product Suite","description":"Overview of the three public plugins in the Bamdra OpenClaw suite."},"headers":[],"relativePath":"guide/products.md","filePath":"guide/products.md","lastUpdated":null}'),l={name:"guide/products.md"};function o(n,e,d,s,u,m){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="product-suite" tabindex="-1">Product Suite <a class="header-anchor" href="#product-suite" aria-label="Permalink to &quot;Product Suite&quot;">​</a></h1><p>The Bamdra OpenClaw suite currently ships as three public plugins, and all three can run independently.</p><h2 id="bamdra-openclaw-memory" tabindex="-1">bamdra-openclaw-memory <a class="header-anchor" href="#bamdra-openclaw-memory" aria-label="Permalink to &quot;bamdra-openclaw-memory&quot;">​</a></h2><p>The main continuity-first memory runtime for OpenClaw.</p><ul><li>topic-aware continuity</li><li>durable fact storage</li><li>compact context assembly</li><li>automatic bootstrap for host config, local memory paths, and bundled identity dependency</li></ul><p>Read more:</p><ul><li><a href="/guide/openclaw-topic-memory">bamdra-openclaw-memory</a></li></ul><h2 id="bamdra-user-bind" tabindex="-1">bamdra-user-bind <a class="header-anchor" href="#bamdra-user-bind" aria-label="Permalink to &quot;bamdra-user-bind&quot;">​</a></h2><p>The identity and profile binding plugin.</p><ul><li>resolves channel-facing sender IDs into stable user boundaries</li><li>stores profiles and mappings locally</li><li>supports Feishu-oriented identity workflows</li><li>can be used independently by any runtime that needs user identity normalization</li></ul><p>Read more:</p><ul><li><a href="/guide/user-bind">bamdra-user-bind</a></li></ul><h2 id="bamdra-memory-vector" tabindex="-1">bamdra-memory-vector <a class="header-anchor" href="#bamdra-memory-vector" aria-label="Permalink to &quot;bamdra-memory-vector&quot;">​</a></h2><p>The semantic recall enhancement plugin.</p><ul><li>keeps Markdown-readable memory artifacts</li><li>adds lightweight local semantic retrieval</li><li>can be used with <code>bamdra-openclaw-memory</code> or as a standalone retrieval helper</li></ul><p>Read more:</p><ul><li><a href="/guide/memory-vector">bamdra-memory-vector</a></li></ul><h2 id="relationship-between-them" tabindex="-1">Relationship between them <a class="header-anchor" href="#relationship-between-them" aria-label="Permalink to &quot;Relationship between them&quot;">​</a></h2><ul><li><code>bamdra-openclaw-memory</code> can run on its own</li><li>when <code>bamdra-openclaw-memory</code> is installed, it will automatically provision <code>bamdra-user-bind</code> if the dependency is available locally through npm package install</li><li><code>bamdra-memory-vector</code> is optional and stays a separate plugin on purpose</li></ul><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><p>All repositories:</p><ul><li><a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></li></ul>',22)])])}const h=a(l,[["render",o]]);export{p as __pageData,h as default};
